function main()
	for packageID, package in pairs(tbl) do
		for serialnumber, box in pairs(package) do
			result, msg = InsertPackage(packageID, box.group, box.id, box.name, box.prob)
			if not result then
				return false, msg
			end
		end
	end
	return true, "success"
end
